export default function Fire() {
  return (
    <div
      style={{
        width: "100vw",
        height: "100vh",
        maxWidth: "100%",
        maxHeight: "100%",
        position: "relative",
        overflow: "hidden",
      }}
    >
      <ASCIIAnimation
        className="w-full h-full"
        frames={frames}
        fps={30}
        chars={" .+*xX#%@"}
        fitToContainer={true}
        appearance={{
          backgroundColor: "transparent",
          borderRadius: 0,
          fontFamily:
            'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace',
          fontSize: 8,
          fontWeight: "normal",
          fontStyle: "normal",
          letterSpacing: 0,
          lineHeight: 1,
          showFrameCounter: false,
          textColor: "#ffffff",
          textEffect: "none",
          useColors: false,
          textEffectThreshold: 0,
        }}
      />
    </div>
  );
}
